import React, { useEffect, useState } from "react";
import {
  Container,
  Box,
  Typography,
  Card,
  CardContent,
  TextField,
  Button,
  IconButton,
  Chip,
  Divider,
  Alert,
} from "@mui/material";
import {
  Add as AddIcon,
  Delete as DeleteIcon,
  ArrowBack as BackIcon,
} from "@mui/icons-material";
import { useNavigate } from "react-router-dom";
import api from "../api";

export default function TaskProgressions() {
  const [progressions, setProgressions] = useState([]);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [steps, setSteps] = useState([{ name: "" }, { name: "" }]);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProgressions();
  }, []);

  const fetchProgressions = async () => {
    try {
      const response = await api.get("/task-progressions");
      setProgressions(response.data.progressions || []);
    } catch (err) {
      console.error(err);
    }
  };

  const handleStepChange = (index, value) => {
    setSteps((prev) =>
      prev.map((step, i) => (i === index ? { ...step, name: value } : step)),
    );
  };

  const addStep = () => {
    setSteps((prev) => [...prev, { name: "" }]);
  };

  const removeStep = (index) => {
    setSteps((prev) => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!name.trim()) {
      setError("Progression name is required.");
      return;
    }


    setLoading(true);

    try {
      const payload = {
        name: name.trim(),
        description: description.trim() || null,
      };

      const response = await api.post("/task-progressions", payload);
      setProgressions((prev) => [response.data.progression, ...prev]);
      setSuccess("Task progression created successfully!");
      setName("");
      setDescription("");
      setSteps([{ name: "" }, { name: "" }]);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create progression");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        backgroundColor: "#F8FAFC",
        minHeight: "calc(100vh - 64px)",
        py: 4,
      }}
    >
      <Container maxWidth="lg">
        <Box sx={{ mb: 4, display: "flex", alignItems: "center", gap: 2 }}>
          <Button
            onClick={() => navigate("/admin/dashboard")}
            startIcon={<BackIcon />}
            sx={{ color: "#64748B", "&:hover": { backgroundColor: "#F1F5F9" } }}
          >
            Back
          </Button>
          <Box>
            <Typography variant="h4" sx={{ fontWeight: 700, color: "#0F172A" }}>
              Task Progressions
            </Typography>
            <Typography variant="body2" sx={{ color: "#64748B", mt: 0.5 }}>
              Create and manage custom workflows for your tasks.
            </Typography>
          </Box>
        </Box>

        <Card sx={{ borderRadius: 2, border: "1px solid #E2E8F0", mb: 4 }}>
          <CardContent sx={{ p: 4 }}>
            <Typography
              variant="h6"
              sx={{ fontWeight: 600, mb: 3, color: "#0F172A" }}
            >
              Create New Progression
            </Typography>

            {success && (
              <Alert severity="success" sx={{ mb: 3, borderRadius: 2 }}>
                {success}
              </Alert>
            )}

            <form onSubmit={handleSubmit}>
              <Box sx={{ mb: 3 }}>
                <TextField
                  fullWidth
                  label="Progression Name"
                  placeholder="e.g., QA Testing Workflow"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  disabled={loading}
                  required
                />
              </Box>

              <Box sx={{ mb: 3 }}>
                <TextField
                  fullWidth
                  label="Description (optional)"
                  placeholder="Describe how this workflow should be used"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  disabled={loading}
                />
              </Box>
              <Button
                type="submit"
                variant="contained"
                disabled={loading}
                sx={{
                  background:
                    "linear-gradient(135deg, #06B6D4 0%, #22D3EE 100%)",
                  "&:hover": {
                    background:
                      "linear-gradient(135deg, #0891B2 0%, #06B6D4 100%)",
                  },
                }}
              >
                {loading ? "Saving..." : "Create Progression"}
              </Button>
            </form>
          </CardContent>
        </Card>

        <Box sx={{ mb: 2 }}>
          <Typography variant="h6" sx={{ fontWeight: 600, color: "#0F172A" }}>
            Existing Progressions
          </Typography>
          <Typography variant="body2" sx={{ color: "#64748B" }}>
            Use these progressions when creating tasks.
          </Typography>
        </Box>

        {progressions.length === 0 ? (
          <Card sx={{ borderRadius: 2, border: "1px solid #E2E8F0" }}>
            <CardContent>
              <Typography variant="body2" sx={{ color: "#64748B" }}>
                No custom progressions yet. Create one to get started.
              </Typography>
            </CardContent>
          </Card>
        ) : (
          <Box sx={{ display: "grid", gap: 2 }}>
            {progressions.map((progression) => (
              <Card
                key={progression.id}
                sx={{ borderRadius: 2, border: "1px solid #E2E8F0" }}
              >
                <CardContent>
                  <Typography
                    variant="subtitle1"
                    sx={{ fontWeight: 600, color: "#0F172A" }}
                  >
                    {progression.name}
                  </Typography>
                  {progression.description && (
                    <Typography
                      variant="body2"
                      sx={{ color: "#64748B", mt: 0.5 }}
                    >
                      {progression.description}
                    </Typography>
                  )}
                  <Divider sx={{ my: 2 }} />
                  <Box sx={{ display: "flex", flexWrap: "wrap", gap: 1 }}>
                    {progression.steps.map((step) => (
                      <Chip
                        key={step.id}
                        label={step.name}
                        sx={{
                          backgroundColor: "#E2E8F0",
                          color: "#0F172A",
                          fontWeight: 500,
                        }}
                      />
                    ))}
                  </Box>
                </CardContent>
              </Card>
            ))}
          </Box>
        )}
      </Container>
    </Box>
  );
}
